  const svelteSource: string = "// In your Svelte component:\nimport ImageCropper from \"lily-design-system-svelte-headless/components/ImageCropper/ImageCropper.svelte\";\n\n<ImageCropper>\n  <!-- content -->\n</ImageCropper>\n";
